#define VECTOR_SIZE (32 * 1024 * 1024)
#define ELEMENTS_PER_THREAD (8)
#define FUSION_DEGREE (4)

template<class T>
inline T conv_int(const int i){ return static_cast<T>(i); }

template<class T>
inline T mad(const T a, const T b, const T c){ return a*b+c; }

template<class T>
inline bool equal(const T a, const T b){ return a==b; }

template <class T, unsigned int granularity, unsigned int fusion_degree, unsigned int compute_iterations, bool TemperateUnroll>
void benchmark_func(T seed, T *data, long size){
	const int blockSize = ELEMENTS_PER_THREAD;
	const int stride = blockSize;
	const int num_threads = omp_get_max_threads();
	const long total_elements = size / sizeof(T);
	const long elements_per_thread = total_elements / num_threads;

	T tmps[granularity];

	#pragma omp parallel for
	for(long tid = 0; tid < num_threads; tid++){
		long idx_start = tid * elements_per_thread * granularity;

		for(int k=0; k<fusion_degree; k++){
			for(long idx = idx_start; idx < idx_start + elements_per_thread * granularity; idx += granularity){
				for(int j=0; j<granularity; j++){
					long access_idx = idx + j*stride + k*elements_per_thread*granularity*num_threads;
					if(access_idx < total_elements)
						tmps[j] = data[access_idx];
					else
						tmps[j] = conv_int<T>(0);

					for(int i=0; i<compute_iterations; i++){
						tmps[j] = mad(tmps[j], tmps[j], seed);
					}
				}

				T sum = conv_int<T>(0);
				for(int j=0; j<granularity; j+=2)
					sum = mad(tmps[j], tmps[j+1], sum);

				if( equal(sum, conv_int<T>(-1)) ) 
					data[idx_start + k*elements_per_thread*granularity*num_threads] = sum;
			}
		}
	}
}

double get_time(){
	return omp_get_wtime();
}

void runbench_warmup(double *cd, long size){
	const long reduced_grid_size = size/(ELEMENTS_PER_THREAD)/128;
	benchmark_func< short, ELEMENTS_PER_THREAD, FUSION_DEGREE, 0, true >(1, (short*)cd, size);
}

int out_config = 1;

template<unsigned int compute_iterations>
void runbench(double *cd, long size, bool doHalfs){
	const long compute_grid_size = size/ELEMENTS_PER_THREAD/FUSION_DEGREE;
	const long long computations = (ELEMENTS_PER_THREAD*(long long)compute_grid_size+(2*ELEMENTS_PER_THREAD*compute_iterations)*(long long)compute_grid_size)*FUSION_DEGREE;
	const long long memoryoperations = size;

	double start_time, end_time;

	start_time = get_time();
	benchmark_func< float, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, false >(1.0f, (float*)cd, size);
	end_time = get_time();
	float kernel_time_mad_sp = (end_time - start_time) * 1000.0f;

	start_time = get_time();
	benchmark_func< double, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, false >(1.0, cd, size);
	end_time = get_time();
	float kernel_time_mad_dp = (end_time - start_time) * 1000.0f;

	float kernel_time_mad_hp = 0.f;
	if( doHalfs ){
		start_time = get_time();
		benchmark_func< short, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, false >(1, (short*)cd, size);
		end_time = get_time();
		kernel_time_mad_hp = (end_time - start_time) * 1000.0f;
	}

	start_time = get_time();
	benchmark_func< int, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, true >(1, (int*)cd, size);
	end_time = get_time();
	float kernel_time_mad_int = (end_time - start_time) * 1000.0f;

	printf("         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
		compute_iterations,
		((double)computations)/((double)memoryoperations*sizeof(float)),
		kernel_time_mad_sp,
		((double)computations)/kernel_time_mad_sp*1000./(double)(1000*1000*1000),
		((double)memoryoperations*sizeof(float))/kernel_time_mad_sp*1000./(1000.*1000.*1000.),
		((double)computations)/((double)memoryoperations*sizeof(double)),
		kernel_time_mad_dp,
		((double)computations)/kernel_time_mad_dp*1000./(double)(1000*1000*1000),
		((double)memoryoperations*sizeof(double))/kernel_time_mad_dp*1000./(1000.*1000.*1000.),
		((double)2*computations)/((double)memoryoperations*sizeof(short)),
		kernel_time_mad_hp,
		((double)2*computations)/kernel_time_mad_hp*1000./(double)(1000*1000*1000),
		((double)memoryoperations*sizeof(short))/kernel_time_mad_hp*1000./(1000.*1000.*1000.),
		((double)computations)/((double)memoryoperations*sizeof(int)),
		kernel_time_mad_int,
		((double)computations)/kernel_time_mad_int*1000./(double)(1000*1000*1000),
		((double)memoryoperations*sizeof(int))/kernel_time_mad_int*1000./(1000.*1000.*1000.) );
}

